// BAD (only compiles before Solidity 0.6):
// arr.length = arr.length + 1; // grow
// arr.length--;                // shrink, can underflow to 2**256 - 1

// GOOD: upgrade the compiler and use push/pop, which manage length safely
pragma solidity ^0.8.20;

uint256[] private arr;

function add(uint256 value) external {
    arr.push(value); // grows by one and initializes the new slot
}

function removeLast() external {
    require(arr.length > 0, "empty");
    arr.pop(); // shrinks by one and clears the removed slot
}

// To "clear" the whole array:
function reset() external {
    delete arr; // sets length to zero and clears elements
}
